(window.webpackJsonp=window.webpackJsonp||[]).push([[584],{879:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">roads</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maximalNetworkRank = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, roads</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> indegree=<span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-number\\">0</span>)\\n    <span class=\\"hljs-keyword\\">let</span> connection={}\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [s,t] <span class=\\"hljs-keyword\\">of</span> roads){\\n        indegree[s]++\\n        indegree[t]++\\n        <span class=\\"hljs-keyword\\">if</span>(connection[s]==<span class=\\"hljs-literal\\">null</span>){\\n            connection[s]={}\\n        }\\n        <span class=\\"hljs-keyword\\">if</span>(connection[t]==<span class=\\"hljs-literal\\">null</span>){\\n            connection[t]={}\\n        }\\n        connection[s][t]=<span class=\\"hljs-literal\\">true</span>\\n        connection[t][s]=<span class=\\"hljs-literal\\">true</span>\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;n;i++){\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=i+<span class=\\"hljs-number\\">1</span>;j&lt;n;j++){\\n            <span class=\\"hljs-keyword\\">let</span> sum=indegree[i]+indegree[j]\\n            <span class=\\"hljs-keyword\\">if</span>(connection[i] &amp;&amp; connection[i][j]){\\n                sum--\\n            }\\n            res=<span class=\\"hljs-built_in\\">Math</span>.max(res,sum)\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"maximal-network-rank","hasThinking":false,"content":"<p><code>n</code> \u5ea7\u57ce\u5e02\u548c\u4e00\u4e9b\u8fde\u63a5\u8fd9\u4e9b\u57ce\u5e02\u7684\u9053\u8def <code>roads</code> \u5171\u540c\u7ec4\u6210\u4e00\u4e2a\u57fa\u7840\u8bbe\u65bd\u7f51\u7edc\u3002\u6bcf\u4e2a <code>roads[i] = [a<sub>i</sub>, b<sub>i</sub>]</code> \u90fd\u8868\u793a\u5728\u57ce\u5e02 <code>a<sub>i</sub></code> \u548c <code>b<sub>i</sub></code> \u4e4b\u95f4\u6709\u4e00\u6761\u53cc\u5411\u9053\u8def\u3002</p>\\n\\n<p>\u4e24\u5ea7\u4e0d\u540c\u57ce\u5e02\u6784\u6210\u7684 <strong>\u57ce\u5e02\u5bf9</strong> \u7684 <strong>\u7f51\u7edc\u79e9</strong> \u5b9a\u4e49\u4e3a\uff1a\u4e0e\u8fd9\u4e24\u5ea7\u57ce\u5e02 <strong>\u76f4\u63a5</strong> \u76f8\u8fde\u7684\u9053\u8def\u603b\u6570\u3002\u5982\u679c\u5b58\u5728\u4e00\u6761\u9053\u8def\u76f4\u63a5\u8fde\u63a5\u8fd9\u4e24\u5ea7\u57ce\u5e02\uff0c\u5219\u8fd9\u6761\u9053\u8def\u53ea\u8ba1\u7b97 <strong>\u4e00\u6b21</strong> \u3002</p>\\n\\n<p>\u6574\u4e2a\u57fa\u7840\u8bbe\u65bd\u7f51\u7edc\u7684 <strong>\u6700\u5927\u7f51\u7edc\u79e9</strong> \u662f\u6240\u6709\u4e0d\u540c\u57ce\u5e02\u5bf9\u4e2d\u7684 <strong>\u6700\u5927\u7f51\u7edc\u79e9</strong> \u3002</p>\\n\\n<p>\u7ed9\u4f60\u6574\u6570 <code>n</code> \u548c\u6570\u7ec4 <code>roads</code>\uff0c\u8fd4\u56de\u6574\u4e2a\u57fa\u7840\u8bbe\u65bd\u7f51\u7edc\u7684 <strong>\u6700\u5927\u7f51\u7edc\u79e9</strong> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/10/11/ex1.png\\" style=\\"width: 292px; height: 172px;\\" /></strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 4, roads = [[0,1],[0,3],[1,2],[1,3]]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a</strong>\u57ce\u5e02 0 \u548c 1 \u7684\u7f51\u7edc\u79e9\u662f 4\uff0c\u56e0\u4e3a\u5171\u6709 4 \u6761\u9053\u8def\u4e0e\u57ce\u5e02 0 \u6216 1 \u76f8\u8fde\u3002\u4f4d\u4e8e 0 \u548c 1 \u4e4b\u95f4\u7684\u9053\u8def\u53ea\u8ba1\u7b97\u4e00\u6b21\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/10/11/ex2.png\\" style=\\"width: 292px; height: 172px;\\" /></strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 5, roads = [[0,1],[0,3],[1,2],[1,3],[2,3],[2,4]]\\n<strong>\u8f93\u51fa\uff1a</strong>5\\n<strong>\u89e3\u91ca\uff1a</strong>\u5171\u6709 5 \u6761\u9053\u8def\u4e0e\u57ce\u5e02 1 \u6216 2 \u76f8\u8fde\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 8, roads = [[0,1],[1,2],[2,3],[2,4],[5,6],[5,7]]\\n<strong>\u8f93\u51fa\uff1a</strong>5\\n<strong>\u89e3\u91ca\uff1a</strong>2 \u548c 5 \u7684\u7f51\u7edc\u79e9\u4e3a 5\uff0c\u6ce8\u610f\u5e76\u975e\u6240\u6709\u7684\u57ce\u5e02\u90fd\u9700\u8981\u8fde\u63a5\u8d77\u6765\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>2 <= n <= 100</code></li>\\n\\t<li><code>0 <= roads.length <= n * (n - 1) / 2</code></li>\\n\\t<li><code>roads[i].length == 2</code></li>\\n\\t<li><code>0 <= a<sub>i</sub>, b<sub>i</sub>\xa0<= n-1</code></li>\\n\\t<li><code>a<sub>i</sub>\xa0!=\xa0b<sub>i</sub></code></li>\\n\\t<li>\u6bcf\u5bf9\u57ce\u5e02\u4e4b\u95f4 <strong>\u6700\u591a\u53ea\u6709\u4e00\u6761</strong>\xa0\u9053\u8def\u76f8\u8fde</li>\\n</ul>\\n","title":"1615. \u6700\u5927\u7f51\u7edc\u79e9","relatedTags":["\u56fe"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1615"}')}}]);